eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   logActivityFromClient: () => (/* binding */ logActivityFromClient)\n/* harmony export */ });\n/**\n * Helper para registrar atividades de auditoria a partir do client (dataService, etc.).\n * Fire-and-forget: não bloqueia a UI.\n */ async function logActivityFromClient(params) {\n    const { action, resourceType, resourceId, programaId, details } = params;\n    try {\n        const res = await fetch(\"/api/audit/log\", {\n            method: \"POST\",\n            headers: {\n                \"Content-Type\": \"application/json\"\n            },\n            credentials: \"include\",\n            body: JSON.stringify({\n                action,\n                resource_type: resourceType,\n                resource_id: resourceId,\n                programa_id: programaId,\n                details,\n                origem: \"api\"\n            })\n        });\n        if (!res.ok) {\n            const text = await res.text();\n            console.error(`[audit] Falha ao registrar: ${action} ${resourceType} ${resourceId ?? \"\"} — status ${res.status}`, text || res.statusText);\n        }\n    } catch (err) {\n        console.error(`[audit] Erro de rede ao registrar: ${action} ${resourceType}`, err instanceof Error ? err.message : err);\n    }\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/services/auditClient.ts\n");

